import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("returns an empty array when given an empty array (empty input → empty output)");

  it.todo("a single live cell at (0,0) dies (0 neighbors) → []");

  it.todo("Rule 1 - Underpopulation: two adjacent cells [(0,1), (1,1)] both die (1 neighbor each) → []");

  it.todo("Rule 4 - Reproduction: dead cell with exactly 3 live neighbors becomes alive — [(0,2), (1,2), (0,1)] produces (1,1) among the live cells of next gen");

  it.todo("Rule 2 - Survival: center cell (1,1) with 3 live neighbors from row [(0,2),(1,2),(2,2)] and (1,0) survives in the next generation");

  it.todo("Rule 3 - Overpopulation: center cell (1,1) with 4 live neighbors (corners + center configuration) dies in next generation");

  it.todo("Block (still life): [(0,0), (1,0), (0,1), (1,1)] is unchanged after one generation");

  it.todo("Blinker (oscillator): vertical [(0,0), (0,1), (0,2)] becomes horizontal [(-1,1), (0,1), (1,1)]");

  it.todo("Handles negative coordinates: a blinker placed at negative coordinates oscillates correctly");
});
